mapper.select:
SELECT a.*, CASE WHEN b.reply_count >= 2 THEN 1 ELSE 0 END AS not_reply, CASE WHEN c.id IS NOT NULL THEN 1 ELSE 0 END AS is_private, CASE a.platform_type WHEN 0 THEN ig.profile_pic_url WHEN 1 THEN yt.avatar_url WHEN 2 THEN tt.author_avatar_url ELSE NULL END AS avatar_url FROM email_push_detail a LEFT JOIN (SELECT push_detail_id, COUNT(*) AS reply_count FROM email_reply GROUP BY push_detail_id) b ON a.id = b.push_detail_id LEFT JOIN store_celebrity_private c on a.username = c.account and a.platform_type = c.platform_type LEFT JOIN ig_celebrity ig ON a.celebrity_id = ig.id AND a.platform_type = 0 LEFT JOIN youtube_celebrity yt ON a.celebrity_id = yt.id AND a.platform_type = 1 LEFT JOIN tiktok_celebrity tt ON a.celebrity_id = tt.id AND a.platform_type = 2
AND a.main_id = #{emailPushDetail.mainId}
AND a.username = #{emailPushDetail.username}
AND a.account = #{emailPushDetail.account}
AND a.platform_type = #{emailPushDetail.platformType}
AND a.nickname = #{emailPushDetail.nickname}
AND a.is_send = #{emailPushDetail.isSend}
AND a.is_opened = #{emailPushDetail.isOpened}
AND a.is_reply = #{emailPushDetail.isReply}
AND a.email LIKE CONCAT('%', #{emailPushDetail.email}, '%')

SELECT COALESCE(COUNT(*), 0) AS totalSentCount, COALESCE(SUM(CASE WHEN is_send = 1 THEN 1 ELSE 0 END), 0) AS actualSentCount, COALESCE(ROUND(SUM(is_send = 1) * 100.0 / NULLIF(COUNT(*), 0), 1), 0.0) AS sendSuccessRate, COALESCE(SUM(CASE WHEN is_send = -1 THEN 1 ELSE 0 END), 0) AS bounceCount, COALESCE(ROUND(SUM(is_send = -1) * 100.0 / NULLIF(COUNT(*), 0), 1), 0.0) AS bounceRate, COALESCE(SUM(CASE WHEN is_opened = 1 THEN 1 ELSE 0 END), 0) AS openCount, COALESCE(ROUND(SUM(CASE WHEN is_opened = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(SUM(is_send = 1), 0), 1), 0.0) AS openRate, COALESCE(SUM(CASE WHEN is_reply = 1 THEN 1 ELSE 0 END), 0) AS replyCount, COALESCE(ROUND(SUM(CASE WHEN is_reply = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(SUM(is_send = 1), 0), 1), 0.0) AS replyRate FROM email_push_detail WHERE is_send IN (1,-1)
AND DATE_FORMAT(send_time, '%Y-%m') = #{query.month}
AND send_time >= #{query.startDate}
AND send_time <= #{query.endDate}
AND counselor_id = #{query.counselorId}

SELECT COALESCE(t.counselor_name, su.username) AS counselorName, COALESCE(COUNT(t.id), 0) AS totalSentCount, COALESCE(SUM(CASE WHEN t.is_send = 1 THEN 1 ELSE 0 END), 0) AS actualSentCount, COALESCE(ROUND(SUM(CASE WHEN t.is_send = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(t.id), 0), 1), 0.0) AS sendSuccessRate, COALESCE(SUM(CASE WHEN t.is_send = -1 THEN 1 ELSE 0 END), 0) AS bounceCount, COALESCE(ROUND(SUM(CASE WHEN t.is_send = -1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(t.id), 0), 1), 0.0) AS bounceRate, COALESCE(SUM(CASE WHEN t.is_opened = 1 THEN 1 ELSE 0 END), 0) AS openCount, COALESCE(ROUND(SUM(CASE WHEN t.is_opened = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(SUM(CASE WHEN t.is_send = 1 THEN 1 ELSE 0 END), 0), 1), 0.0) AS openRate, COALESCE(SUM(CASE WHEN t.is_reply = 1 THEN 1 ELSE 0 END), 0) AS replyCount, COALESCE(ROUND(SUM(CASE WHEN t.is_reply = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(SUM(CASE WHEN t.is_send = 1 THEN 1 ELSE 0 END), 0), 1), 0.0) AS replyRate FROM sys_user su LEFT JOIN email_push_detail t ON t.counselor_id = su.id AND t.is_send IN (1,-1)
AND DATE_FORMAT(t.send_time, '%Y-%m') = #{query.month}
AND t.send_time >= #{query.startDate}
AND t.send_time <= #{query.endDate}
WHERE su.user_type = 4 AND su.is_leave = 0 AND su.status = 1 AND su.del_flag= 0 GROUP BY su.id ORDER BY COALESCE(COUNT(*), 0) DESC;

WITH RECURSIVE date_series AS ( SELECT DATE(#{query.startDate}) AS stat_date UNION ALL SELECT stat_date + INTERVAL 1 DAY FROM date_series WHERE stat_date + INTERVAL 1 DAY <= DATE(#{query.endDate}) )
WITH RECURSIVE date_bounds AS ( SELECT DATE(MIN(send_time)) AS min_date, DATE(MAX(send_time)) AS max_date FROM email_push_detail WHERE is_send IN (1,-1) ), date_series AS ( SELECT min_date AS stat_date FROM date_bounds UNION ALL SELECT stat_date + INTERVAL 1 DAY FROM date_series WHERE stat_date <(SELECT max_date FROM date_bounds) )
SELECT ds.stat_date AS `date`, COALESCE(COUNT(t.id), 0) AS totalSentCount, COALESCE(SUM(CASE WHEN t.is_send = 1 THEN 1 ELSE 0 END), 0) AS actualSentCount, COALESCE(ROUND(SUM(t.is_send = 1) * 100.0 / NULLIF(COUNT(t.id), 0), 1), 0.0) AS sendSuccessRate, COALESCE(SUM(CASE WHEN t.is_send = -1 THEN 1 ELSE 0 END), 0) AS bounceCount, COALESCE(ROUND(SUM(t.is_send = -1) * 100.0 / NULLIF(COUNT(t.id), 0), 1), 0.0) AS bounceRate, COALESCE(SUM(CASE WHEN t.is_opened = 1 THEN 1 ELSE 0 END), 0) AS openCount, COALESCE(ROUND(SUM(t.is_opened = 1) * 100.0 / NULLIF(SUM(t.is_send = 1), 0), 1), 0.0) AS openRate, COALESCE(SUM(CASE WHEN t.is_reply = 1 THEN 1 ELSE 0 END), 0) AS replyCount, COALESCE(ROUND(SUM(t.is_reply = 1) * 100.0 / NULLIF(SUM(t.is_send = 1), 0), 1), 0.0) AS replyRate FROM date_series ds LEFT JOIN email_push_detail t ON t.send_time >= ds.stat_date AND t.send_time < ds.stat_date + INTERVAL 1 DAY AND t.is_send IN (1,-1)
AND DATE_FORMAT(t.send_time, '%Y-%m') = #{query.month}
AND t.counselor_id = #{query.counselorId}
GROUP BY ds.stat_date ORDER BY ds.stat_date;

SELECT COALESCE(COUNT(*), 0) AS totalSentCount, COALESCE(SUM(CASE WHEN d.is_send = 1 THEN 1 ELSE 0 END), 0) AS actualSentCount, COALESCE(ROUND(SUM(CASE WHEN d.is_send = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(*), 0), 1), 0.0) AS sendSuccessRate, COALESCE(SUM(CASE WHEN d.is_send = -1 THEN 1 ELSE 0 END), 0) AS bounceCount, COALESCE(ROUND(SUM(CASE WHEN d.is_send = -1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(*), 0), 1), 0.0) AS bounceRate, COALESCE(SUM(CASE WHEN d.is_opened = 1 THEN 1 ELSE 0 END), 0) AS openCount, COALESCE(ROUND(SUM(CASE WHEN d.is_opened = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(SUM(CASE WHEN d.is_send = 1 THEN 1 ELSE 0 END), 0), 1), 0.0) AS openRate, COALESCE(SUM(CASE WHEN d.is_reply = 1 THEN 1 ELSE 0 END), 0) AS replyCount, COALESCE(ROUND(SUM(CASE WHEN d.is_reply = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(SUM(CASE WHEN d.is_send = 1 THEN 1 ELSE 0 END), 0), 1), 0.0) AS replyRate FROM email_push_detail d INNER JOIN email_push_main m ON d.main_id = m.id AND m.business_type = 1 WHERE d.is_send IN (1,-1)
AND DATE_FORMAT(d.send_time, '%Y-%m') = #{query.month}
AND d.send_time >= #{query.startDate}
AND d.send_time <= #{query.endDate}
AND d.counselor_id = #{query.counselorId}

SELECT COALESCE(t.counselor_name, su.username) AS counselorName, COALESCE(COUNT(t.id), 0) AS totalSentCount, COALESCE(SUM(CASE WHEN t.is_send = 1 THEN 1 ELSE 0 END), 0) AS actualSentCount, COALESCE(ROUND(SUM(CASE WHEN t.is_send = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(t.id), 0), 1), 0.0) AS sendSuccessRate, COALESCE(SUM(CASE WHEN t.is_send = -1 THEN 1 ELSE 0 END), 0) AS bounceCount, COALESCE(ROUND(SUM(CASE WHEN t.is_send = -1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(t.id), 0), 1), 0.0) AS bounceRate, COALESCE(SUM(CASE WHEN t.is_opened = 1 THEN 1 ELSE 0 END), 0) AS openCount, COALESCE(ROUND(SUM(CASE WHEN t.is_opened = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(SUM(CASE WHEN t.is_send = 1 THEN 1 ELSE 0 END), 0), 1), 0.0) AS openRate, COALESCE(SUM(CASE WHEN t.is_reply = 1 THEN 1 ELSE 0 END), 0) AS replyCount, COALESCE(ROUND(SUM(CASE WHEN t.is_reply = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(SUM(CASE WHEN t.is_send = 1 THEN 1 ELSE 0 END), 0), 1), 0.0) AS replyRate FROM sys_user su LEFT JOIN email_push_detail t ON t.counselor_id = su.id AND t.is_send IN (1,-1) AND EXISTS ( SELECT 1 FROM email_push_main m WHERE m.id = t.main_id AND m.business_type = 1 )
AND DATE_FORMAT(t.send_time, '%Y-%m') = #{query.month}
AND t.send_time >= #{query.startDate}
AND t.send_time <= #{query.endDate}
WHERE su.user_type = 10 AND su.is_leave = 0 AND su.status = 1 AND su.del_flag= 0 GROUP BY su.id ORDER BY COALESCE(COUNT(*), 0) DESC;

WITH RECURSIVE date_series AS ( SELECT DATE(#{query.startDate}) AS stat_date UNION ALL SELECT stat_date + INTERVAL 1 DAY FROM date_series WHERE stat_date + INTERVAL 1 DAY <= DATE(#{query.endDate}) )
WITH RECURSIVE date_bounds AS ( SELECT DATE(MIN(t.send_time)) AS min_date, DATE(MAX(t.send_time)) AS max_date FROM email_push_detail t INNER JOIN email_push_main m ON t.main_id = m.id AND m.business_type = 1 WHERE t.is_send IN (1,-1) ), date_series AS ( SELECT min_date AS stat_date FROM date_bounds UNION ALL SELECT stat_date + INTERVAL 1 DAY FROM date_series WHERE stat_date <(SELECT max_date FROM date_bounds) )
SELECT ds.stat_date AS `date`, COALESCE(COUNT(t.id), 0) AS totalSentCount, COALESCE(SUM(CASE WHEN t.is_send = 1 THEN 1 ELSE 0 END), 0) AS actualSentCount, COALESCE(ROUND(SUM(CASE WHEN t.is_send = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(t.id), 0), 1), 0.0) AS sendSuccessRate, COALESCE(SUM(CASE WHEN t.is_send = -1 THEN 1 ELSE 0 END), 0) AS bounceCount, COALESCE(ROUND(SUM(CASE WHEN t.is_send = -1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(t.id), 0), 1), 0.0) AS bounceRate, COALESCE(SUM(CASE WHEN t.is_opened = 1 THEN 1 ELSE 0 END), 0) AS openCount, COALESCE(ROUND(SUM(CASE WHEN t.is_opened = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(SUM(CASE WHEN t.is_send = 1 THEN 1 ELSE 0 END), 0), 1), 0.0) AS openRate, COALESCE(SUM(CASE WHEN t.is_reply = 1 THEN 1 ELSE 0 END), 0) AS replyCount, COALESCE(ROUND(SUM(CASE WHEN t.is_reply = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(SUM(CASE WHEN t.is_send = 1 THEN 1 ELSE 0 END), 0), 1), 0.0) AS replyRate FROM date_series ds LEFT JOIN email_push_detail t ON t.send_time >= ds.stat_date AND t.send_time < ds.stat_date + INTERVAL 1 DAY AND t.is_send IN (1,-1) AND EXISTS ( SELECT 1 FROM email_push_main m WHERE m.id = t.main_id AND m.business_type = 1 )
AND DATE_FORMAT(t.send_time, '%Y-%m') = #{query.month}
AND t.counselor_id = #{query.counselorId}
GROUP BY ds.stat_date ORDER BY ds.stat_date;
